DROP TABLE IF EXISTS `catchpolygons`;
CREATE TABLE `catchpolygons`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `coordinates` json NOT NULL COMMENT 'Array of lat/lng coordinates forming the polygon',
  `zoneType` enum('fishing','restricted','conservation','special') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'fishing',
  `fishTypes` json NULL COMMENT 'Array of fish types allowed in this zone',
  `regulations` json NULL COMMENT 'Fishing regulations for this zone',
  `maxVessels` int NULL DEFAULT NULL COMMENT 'Maximum number of vessels allowed',
  `seasonalRestrictions` json NULL COMMENT 'Seasonal fishing restrictions',
  `isActive` tinyint(1) NULL DEFAULT 1,
  `color` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '#3b82f6' COMMENT 'Hex color for map display',
  `createdBy` int NULL DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `createdBy`(`createdBy` ASC) USING BTREE,
  CONSTRAINT `catchpolygons_ibfk_1` FOREIGN KEY (`createdBy`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

