DROP TABLE IF EXISTS `fishing_points`;
CREATE TABLE `fishing_points`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `trip_id` int NOT NULL,
  `kapal_id` int NOT NULL,
  `location` json NOT NULL,
  `depth_meters` decimal(10, 2) NULL DEFAULT NULL,
  `action_type` enum('net_deployed','net_retrieved') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'net_deployed',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `hasil_tangkap_id` int NULL DEFAULT NULL,
  `timestamp` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `hasil_tangkap_ids` json NULL,
  `submitted_by` int NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `trip_id`(`trip_id` ASC) USING BTREE,
  INDEX `kapal_id`(`kapal_id` ASC) USING BTREE,
  INDEX `fk_fp_hasil_tangkap`(`hasil_tangkap_id` ASC) USING BTREE,
  CONSTRAINT `fishing_points_ibfk_1` FOREIGN KEY (`trip_id`) REFERENCES `trips` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fishing_points_ibfk_2` FOREIGN KEY (`kapal_id`) REFERENCES `kapals` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_fp_hasil_tangkap` FOREIGN KEY (`hasil_tangkap_id`) REFERENCES `hasil_tangkap` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

