-- ----------------------------
-- Table structure for harbor_zones
-- ----------------------------
DROP TABLE IF EXISTS `harbor_zones`;
CREATE TABLE `harbor_zones`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `coordinates` json NOT NULL,
  `shape_type` enum('circle','polygon') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'circle' COMMENT 'Shape type: circle (uses radius) or polygon (uses coordinates array)',
  `type` enum('harbor','port','anchorage','restricted','conservation') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'harbor',
  `radius` int NULL DEFAULT 1000 COMMENT 'Radius in meters',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `capacity` int NULL DEFAULT NULL COMMENT 'Maximum vessel capacity',
  `facilities` json NULL COMMENT 'Available facilities',
  `is_active` tinyint(1) NULL DEFAULT 1,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `color` varchar(7) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '#10b981' COMMENT 'Zone color in hex format',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 20 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

