-- ----------------------------
-- Table structure for hasil_tangkap
-- ----------------------------
DROP TABLE IF EXISTS `hasil_tangkap`;
CREATE TABLE `hasil_tangkap`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `kapal_id` int NOT NULL,
  `trip_id` int NULL DEFAULT NULL,
  `jenis_ikan` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `berat_kg` decimal(10, 2) NOT NULL,
  `berat_mobile` decimal(10, 2) NULL DEFAULT NULL,
  `berat_iot` decimal(10, 2) NULL DEFAULT NULL,
  `harga_per_kg` decimal(10, 2) NULL DEFAULT NULL,
  `total_harga` decimal(12, 2) NULL DEFAULT NULL,
  `lokasi` json NULL,
  `tanggal_tangkap` datetime NOT NULL,
  `metode_tangkap` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `kondisi_cuaca` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `catatan` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `status` enum('draft','confirmed','sold') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'confirmed',
  `extendedData` json NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `tax_percentage` decimal(5, 2) NULL DEFAULT 10.00,
  `tax_amount` decimal(12, 2) NULL DEFAULT NULL,
  `net_value` decimal(12, 2) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `kapal_id`(`kapal_id` ASC) USING BTREE,
  INDEX `trip_id`(`trip_id` ASC) USING BTREE,
  CONSTRAINT `hasil_tangkap_ibfk_1` FOREIGN KEY (`kapal_id`) REFERENCES `kapals` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `hasil_tangkap_ibfk_2` FOREIGN KEY (`trip_id`) REFERENCES `trips` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 49 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

