-- ----------------------------
-- Table structure for kapals
-- ----------------------------
DROP TABLE IF EXISTS `kapals`;
CREATE TABLE `kapals`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `namaKapal` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `nomorRegistrasi` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `nomorKapal` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `pemilik` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `tipeKapal` enum('penangkap_ikan','pengangkut_ikan','penelitian','patroli') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'penangkap_ikan',
  `spesifikasi` json NULL,
  `alatTangkap` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `panjangKapal` decimal(5, 2) NULL DEFAULT NULL,
  `lebarKapal` decimal(5, 2) NULL DEFAULT NULL,
  `tinggiKapal` decimal(10, 2) NULL DEFAULT NULL,
  `beratKapal` decimal(10, 2) NULL DEFAULT NULL,
  `netTonnage` decimal(10, 2) NULL DEFAULT NULL COMMENT 'Net Tonnage (NT) - kapasitas ruang muat',
  `mesin` json NULL,
  `gps` json NULL,
  `foto` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `statusOperasional` enum('active','maintenance','inactive') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'active',
  `statusPelayaran` enum('sailing','docked','maintenance','idle') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'docked',
  `nahkodaId` int NULL DEFAULT NULL,
  `dokumen` json NULL,
  `sertifikatJalan` json NULL,
  `dataBahanBakar` json NULL,
  `asuransi` json NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `vesselId` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `storageData` json NULL,
  `gpsDeviceId` int NULL DEFAULT NULL COMMENT 'ID perangkat GPS dari tabel perangkats',
  `dataEs` json NULL COMMENT 'Ice data for mobile app',
  `iceData` json NULL,
  `lastPosition` json NULL COMMENT 'Last known position from any trip',
  `lastPositionUpdate` datetime NULL DEFAULT NULL COMMENT 'Timestamp of last position update',
  `pelabuhanAsal` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Nama pelabuhan asal (teks bebas)',
  `pelabuhanAsalId` int NULL DEFAULT NULL COMMENT 'FK ke harbor_zones - pelabuhan asal/pangkalan tetap kapal',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `idx_vessel_id`(`vesselId` ASC) USING BTREE,
  UNIQUE INDEX `idx_nomor_reg`(`nomorRegistrasi` ASC) USING BTREE,
  INDEX `idx_kapals_gps_device`(`gpsDeviceId` ASC) USING BTREE,
  INDEX `fk_kapals_pelabuhan_asal`(`pelabuhanAsalId` ASC) USING BTREE,
  CONSTRAINT `fk_kapals_gps_device` FOREIGN KEY (`gpsDeviceId`) REFERENCES `perangkats` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_kapals_pelabuhan_asal` FOREIGN KEY (`pelabuhanAsalId`) REFERENCES `harbor_zones` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

