-- ----------------------------
-- Table structure for operational_tasks
-- ----------------------------
DROP TABLE IF EXISTS `operational_tasks`;
CREATE TABLE `operational_tasks`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `task_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `task_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `task_type` enum('preparation','departure','fishing','return','maintenance') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'preparation',
  `assigned_to` enum('nahkoda','abk','all') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'all',
  `scheduled_date` date NOT NULL,
  `scheduled_time` time NOT NULL,
  `priority` enum('low','medium','high','urgent') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'medium',
  `status` enum('pending','in_progress','completed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'pending',
  `completed_at` datetime NULL DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `catch_polygon_id` int NULL DEFAULT NULL,
  `vessel_id` int NOT NULL,
  `nahkoda_id` int NULL DEFAULT NULL,
  `abk_ids` json NULL,
  `location_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `harbor_zone_id` int NULL DEFAULT NULL,
  `catch_polygon_ids` json NULL COMMENT 'Array of catch polygon IDs for multiple fishing zones',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `catch_polygon_id`(`catch_polygon_id` ASC) USING BTREE,
  INDEX `vessel_id`(`vessel_id` ASC) USING BTREE,
  INDEX `nahkoda_id`(`nahkoda_id` ASC) USING BTREE,
  INDEX `fk_operational_tasks_harbor_zone`(`harbor_zone_id` ASC) USING BTREE,
  CONSTRAINT `fk_operational_tasks_harbor_zone` FOREIGN KEY (`harbor_zone_id`) REFERENCES `harbor_zones` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `operational_tasks_nahkoda_fk` FOREIGN KEY (`nahkoda_id`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `operational_tasks_vessel_fk` FOREIGN KEY (`vessel_id`) REFERENCES `kapals` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 107 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

