-- Records of password_reset_tokens
-- ----------------------------

-- ----------------------------
-- Table structure for perangkats
-- ----------------------------
DROP TABLE IF EXISTS `perangkats`;
CREATE TABLE `perangkats`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `namaPerangkat` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'Nama perangkat (GPS, Radio, Sonar, dll)',
  `jenisPerangkat` enum('gps','radio','sonar','radar','kompas','mesin','alat_tangkap','keselamatan','lainnya') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'lainnya',
  `merk` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Merk/brand perangkat',
  `model` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Model perangkat',
  `nomorSeri` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Serial number perangkat',
  `tahunPembuatan` int NULL DEFAULT NULL,
  `kondisi` enum('baik','rusak_ringan','rusak_berat','tidak_berfungsi') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'baik',
  `statusOperasional` enum('aktif','maintenance','rusak','tidak_digunakan') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'aktif',
  `tanggalPembelian` datetime NULL DEFAULT NULL,
  `hargaPembelian` decimal(15, 2) NULL DEFAULT NULL COMMENT 'Harga pembelian dalam rupiah',
  `spesifikasi` json NULL COMMENT 'Spesifikasi teknis perangkat',
  `foto` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'Path foto perangkat',
  `keterangan` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'Keterangan tambahan',
  `kapalId` int NULL DEFAULT NULL COMMENT 'ID kapal yang menggunakan perangkat (null jika perangkat cadangan)',
  `createdBy` int NULL DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `kapalId`(`kapalId` ASC) USING BTREE,
  INDEX `createdBy`(`createdBy` ASC) USING BTREE,
  CONSTRAINT `perangkats_ibfk_1` FOREIGN KEY (`kapalId`) REFERENCES `kapals` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `perangkats_ibfk_2` FOREIGN KEY (`createdBy`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 27 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

