-- ----------------------------
-- Table structure for trip_tasks
-- ----------------------------
DROP TABLE IF EXISTS `trip_tasks`;
CREATE TABLE `trip_tasks`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `trip_id` int NOT NULL,
  `task_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `task_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `task_type` enum('preparation','departure','fishing','return','maintenance') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'preparation',
  `assigned_to` enum('nahkoda','abk','all') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'all',
  `scheduled_date` datetime NOT NULL,
  `scheduled_time` time NOT NULL,
  `priority` enum('low','medium','high','urgent') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'medium',
  `status` enum('pending','in_progress','completed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending',
  `completed_at` datetime NULL DEFAULT NULL,
  `completed_by` int NULL DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `catch_polygon_id` int NULL DEFAULT NULL,
  `location_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `vessel_id` int NULL DEFAULT NULL,
  `nahkoda_id` int NULL DEFAULT NULL,
  `abk_ids` json NULL,
  `reminder_sent` tinyint(1) NULL DEFAULT 0,
  `created_by` int NULL DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `harborZoneId` int NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `trip_id`(`trip_id` ASC) USING BTREE,
  INDEX `fk_trip_tasks_harbor_zone`(`harborZoneId` ASC) USING BTREE,
  CONSTRAINT `fk_trip_tasks_harbor_zone` FOREIGN KEY (`harborZoneId`) REFERENCES `harbor_zones` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `trip_tasks_ibfk_1` FOREIGN KEY (`trip_id`) REFERENCES `trips` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of trip_tasks
-- ----------------------------

-- ----------------------------
-- Table structure for trips
-- ----------------------------
DROP TABLE IF EXISTS `trips`;
CREATE TABLE `trips`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `kapalId` int NOT NULL,
  `nahkodaId` int NOT NULL,
  `awakKapal` json NULL,
  `tanggalBerangkat` datetime NOT NULL,
  `estimasiPulang` datetime NOT NULL,
  `tanggalPulangAktual` datetime NULL DEFAULT NULL,
  `durasi` int NOT NULL,
  `areaTangkap` json NULL,
  `targetIkan` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `estimasiBerat` int NULL DEFAULT NULL,
  `beratAktual` int NULL DEFAULT NULL,
  `status` enum('menunggu_dokumen','menunggu_izin','disetujui','ditolak','menunggu_mulai','sedang_melaut','selesai','darurat') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'menunggu_dokumen',
  `perizinan` json NULL,
  `kondisiCuaca` json NULL,
  `tracking` json NULL,
  `laporan` json NULL,
  `biaya` json NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `harborZoneId` int NULL DEFAULT NULL,
  `currentLocation` json NULL COMMENT 'Real-time vessel location {lat, lng, timestamp}',
  `taskId` int NULL DEFAULT NULL COMMENT 'Reference to original operational task if trip was created from task',
  `catatan` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'Additional notes or comments about the trip',
  `catchPolygonIds` json NULL COMMENT 'Array of catch polygon IDs for multiple fishing zones',
  `tripDocuments` json NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `nahkodaId`(`nahkodaId` ASC) USING BTREE,
  INDEX `fk_trips_kapal`(`kapalId` ASC) USING BTREE,
  INDEX `fk_trips_harbor_zone`(`harborZoneId` ASC) USING BTREE,
  INDEX `trips_taskId_foreign_idx`(`taskId` ASC) USING BTREE,
  CONSTRAINT `fk_trips_harbor_zone` FOREIGN KEY (`harborZoneId`) REFERENCES `harbor_zones` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_trips_kapal` FOREIGN KEY (`kapalId`) REFERENCES `kapals` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `trips_taskId_foreign_idx` FOREIGN KEY (`taskId`) REFERENCES `operational_tasks` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 59 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

