-- ----------------------------
-- Table structure for vessel_crews
-- ----------------------------
DROP TABLE IF EXISTS `vessel_crews`;
CREATE TABLE `vessel_crews`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `kapal_id` int NOT NULL,
  `user_id` int NOT NULL,
  `role` enum('nahkoda','abk') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_active` tinyint(1) NULL DEFAULT 1,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `kapal_id`(`kapal_id` ASC) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE,
  CONSTRAINT `vessel_crews_ibfk_1` FOREIGN KEY (`kapal_id`) REFERENCES `kapals` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `vessel_crews_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 101 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

