-- ----------------------------
-- Table structure for weather
-- ----------------------------
DROP TABLE IF EXISTS `weather`;
CREATE TABLE `weather`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `tanggal` datetime NOT NULL,
  `lokasi` json NULL COMMENT 'Location data with name and coordinates',
  `suhu` float NULL DEFAULT NULL COMMENT 'Temperature in Celsius',
  `kecepatanAngin` float NULL DEFAULT NULL COMMENT 'Wind speed in km/h',
  `arahAngin` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Wind direction',
  `tinggiGelombang` float NULL DEFAULT NULL COMMENT 'Wave height in meters',
  `visibility` float NULL DEFAULT NULL COMMENT 'Visibility in km',
  `tekananUdara` float NULL DEFAULT NULL COMMENT 'Air pressure in hPa',
  `kelembaban` int NULL DEFAULT NULL COMMENT 'Humidity percentage',
  `kondisi` enum('cerah','berawan','mendung','hujan_ringan','hujan_lebat','badai') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'berawan',
  `peringatan` json NULL COMMENT 'Warning data with level and message',
  `prediksi24Jam` json NULL COMMENT '24-hour forecast data',
  `source` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'OpenWeatherMap' COMMENT 'Data source',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

